[System.IO.File]::WriteAllBytes(
  (Join-Path (Get-Location) "public\brand\logo-mark.png"),
  [Convert]::FromBase64String(($logoBase64 -replace "\s",""))
)

$pagePath = (Resolve-Path ".\src\app\page.tsx").Path
$page = [System.IO.File]::ReadAllText($pagePath)

$oldLogoPattern = '(?s)<Link href="/" className="flex shrink-0 items-center gap-2 rounded border border-transparent px-2 py-1 hover:border-white">.*?</Link>'

$newLogo = @'
<Link
  href="/"
  aria-label="WHOKEAS ALL IN home"
  className="flex min-w-[194px] shrink-0 items-center gap-3 rounded-md border border-transparent px-2 py-1.5 transition hover:border-white/70"
>
  <div className="relative h-12 w-[72px] shrink-0">
    <Image
      src="/brand/logo-mark.png"
      alt=""
      fill
      priority
      sizes="72px"
      className="object-contain drop-shadow-[0_4px_10px_rgba(243,182,31,0.18)]"
    />
  </div>

  <div className="hidden leading-none sm:block">
    <div className="text-[17px] font-black tracking-[0.12em] text-white">
      WHOKEAS
    </div>
    <div className="mt-1.5 text-[11px] font-black tracking-[0.34em] text-[#f3b61f]">
      ALL IN
    </div>
  </div>
</Link>
'@

$updated = [regex]::Replace($page, $oldLogoPattern, $newLogo, 1)

if ($updated -eq $page) {
  throw "Header logo block was not found. The page may have been changed."
}

$allPattern = '\{index === 0 \? "[^"]*All" : department\}'

$allReplacement = @'
{index === 0 ? (
  <span className="flex items-center gap-2">
    <svg
      viewBox="0 0 24 24"
      aria-hidden="true"
      className="h-5 w-5"
      fill="none"
      stroke="currentColor"
      strokeWidth="2"
      strokeLinecap="round"
    >
      <path d="M4 6h16M4 12h16M4 18h16" />
    </svg>
    <span>All</span>
  </span>
) : (
  department
)}
'@

$updated2 = [regex]::Replace($updated, $allPattern, $allReplacement, 1)

if ($updated2 -eq $updated) {
  Write-Warning 'The corrupted "All" label was not found; the logo was still fixed.'
}

[System.IO.File]::WriteAllText($pagePath, $updated2, $utf8)

Remove-Item -Recurse -Force ".\.next" -ErrorAction SilentlyContinue

Write-Host ""
Write-Host "WHOKEAS header upgraded successfully." -ForegroundColor Green
Write-Host "- Clean transparent WAI monogram installed" -ForegroundColor Green
Write-Host "- Repeated square logo removed" -ForegroundColor Green
Write-Host '- Corrupted "All" navigation label fixed' -ForegroundColor Green
Write-Host ""
Write-Host "Run: npm run dev" -ForegroundColor Yellow
